<template>
  <div class="wrapper">
    <img src="http://www.dell-lee.com/imgs/vue3/user.png" />
    <div class="wrapper_input">
      <input class="wrapper_input_content" placeholder="请输入用户名" v-model="username" />
    </div>
    <div class="wrapper_input">
      <input class="wrapper_input_content" type="password" placeholder="请输入密码" v-model="password" autocomplete="new-password" />
    </div>
    <div class="wrapper_login-button" @click="handleLogin">登录</div>
    <div class="wrapper_login-link" @click="handleRegister">立即注册</div>
  </div>
  <Toast v-if="show" :message="toastMessage" />
</template>

<script>
import { reactive, toRefs } from 'vue'
import { useRouter } from "vue-router"
import { post } from '../../utils/request'
import Toast, { useToastEffect } from '../../components/Toast.vue'

const useLoginEffect = (showToast) => {  // 登录逻辑
  const router = useRouter()
  const data = reactive({ username: '', password: '' })
  const handleLogin = async () => {
    try {
      const { username, password } = data
      if (!username || !password) {
        showToast('用户名或密码填写错误, 请重新填写')
        return
      }
      const result = await post('/api/user/login', {
        username: data.username,
        password: data.password
      })
      if (result?.errno === 0) {
        localStorage.isLogin = true
        router.push({ path: '/' })
      } else {
        showToast('登陆失败')
      }
    } catch(e) {
      showToast('请求失败')
    }
  }
  const { username, password } = toRefs(data)
  return { username, password, handleLogin }
}

const useRegisterEffect = () => {  // 跳转注册页面逻辑
  const router = useRouter()
  const handleRegister = () => {
    router.push({ path: '/register', query: { type: 1 } })
  }
  return { handleRegister }
}

export default {
  name: 'Login',
  components: {
    Toast
  },
  setup() {  
    // 最好是只负责代码执行的流程
    // 不用放太多的逻辑
    const { show, toastMessage, showToast } = useToastEffect()
    const { username, password, handleLogin } = useLoginEffect(showToast)
    const { handleRegister } = useRegisterEffect()
    
    return { username, password, show, toastMessage, handleLogin, handleRegister }
  }
}
</script>

<style lang="scss" scoped>
  @import '../../styles/variables.scss';
  .wrapper {
    position: absolute;
    top: 50%;
    left: 0;
    right: 0;
    transform: translateY(-50%);
    img {
      display: block;
      margin: 0 auto .4rem auto;
      width: .66rem;
      height: .66rem;
    }
    &_input {
      height: .48rem;
      padding: 0 .16rem;
      box-sizing: border-box;
      margin: 0 .4rem .16rem .4rem;
      background: #f9f9f9;
      border: 1px solid rgba(0, 0, 0, .1);
      border-radius: .06rem;
      &_content {
        line-height: .48rem;
        border: none;  // 去除边框
        outline: none;  // 选中时去除边框
        width: 100%;
        background: none;
        font-size: .16rem;
        color: $content-notice-fontcolor;
        &::placeholder {
          color: $content-notice-fontcolor;
        }
      }
    }
    &_login-button {
      text-align: center;
      margin: .32rem .4rem .16rem .4rem;
      line-height: .48rem;
      font-size: .16rem;
      background: $btn-bgColor;
      color: $bgColor;
      box-shadow: 0 .04rem .08rem 0 rgba(0, 145, 255, .32);
      border-radius: .04rem;
    }
    &_login-link {
      text-align: center;
      font-size: .14rem;
      color: $content-notice-fontcolor;
    }
  }
</style>